INSERT INTO PROGRAM
	( PROGRAM_ID
	, PROGRAM_NM
	, PROGRAM_TYPE
	, VENUE_ID
	, DESCRIPTION
	, AGE_LIMIT
	, RUNNING_TIME
	, POSTER_IMG
	, START_DATE
	, END_DATE
	, OPEN_TIME
	, CLOSE_TIME
	, SESSION_COUNT
	, FIRST_SESSION_TIME
	, SESSION_INTERVAL
	, DEFAULT_ONLINE_CAP
	, DEFAULT_OFFLINE_CAP
	, USE_YN
	, REG_USER
	, REG_DT )
VALUES
	( #{programId}
	, #{programNm}
	, #{programType}
	, #{venueId}
	, #{description}
	, #{ageLimit}
	, #{runningTime}
	, #{posterImg}
	, #{startDate, jdbcType=DATE}
	, #{endDate, jdbcType=DATE}
	, #{openTime}NULL
	, #{closeTime}NULL
	, #{sessionCount, jdbcType=INTEGER}
	, #{firstSessionTime}NULL
	, #{sessionInterval, jdbcType=INTEGER}
	, #{defaultOnlineCap, jdbcType=INTEGER}
	, #{defaultOfflineCap, jdbcType=INTEGER}
	, #{useYn}
	, #{regUser}
	, GETDATE() )

mapper.update:
UPDATE PROGRAM
SET PROGRAM_NM   = #{programNm}
  , PROGRAM_TYPE = #{programType}
  , VENUE_ID     = #{venueId}
  , DESCRIPTION  = #{description}
  , AGE_LIMIT    = #{ageLimit}
  , RUNNING_TIME = #{runningTime}
  , POSTER_IMG   = #{posterImg}
  , START_DATE   = #{startDate, jdbcType=DATE}
  , END_DATE     = #{endDate, jdbcType=DATE}
  , OPEN_TIME    = #{openTime}NULL
  , CLOSE_TIME   = #{closeTime}NULL
  , SESSION_COUNT      = #{sessionCount, jdbcType=INTEGER}
  , FIRST_SESSION_TIME = #{firstSessionTime}NULL
  , SESSION_INTERVAL   = #{sessionInterval, jdbcType=INTEGER}
  , DEFAULT_ONLINE_CAP = #{defaultOnlineCap, jdbcType=INTEGER}
  , DEFAULT_OFFLINE_CAP = #{defaultOfflineCap, jdbcType=INTEGER}
  , USE_YN       = #{useYn}
  , REG_USER     = #{regUser}
WHERE PROGRAM_ID = #{programId}

